class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        const int MOD = 1e9 + 7;
        vector<int> dp(n + 1);
        dp[1] = 1;
        int share = 0;
        for (int i = 2; i <= n; i++) {
            if (i >= delay + 1) {
                share = (share + dp[i - delay]) % MOD;
            }
            if (i >= forget + 1) {
                share = (share - dp[i - forget] + MOD) % MOD;
            }
            dp[i] = (dp[i] + share) % MOD;
        }
        int ans = 0;
        for (int i = max(1, n - forget + 1); i <= n; i++) {
            ans = (ans + dp[i]) % MOD;
        }
        return ans;
    }
};

